const PROCESSING_FEE = 5;
// Premiums are accumulated in tenths of a gold piece so we can apply
// fractional surcharges/discounts with integer math and round once at the end
// (avoids floating-point artifacts like 100 * 1.1 = 110.00000000000001).
const TENTHS_PER_UNIT = 10;
const FIRST_INSURANCE_TENTHS = 1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const itemPremiumTenths = (item: Item): number =>
  basePremium(item) * (TENTHS_PER_UNIT + FIRST_INSURANCE_TENTHS);

const quote = (step: QuoteStep): QuoteResult => {
  const itemsTotalTenths = step.items.reduce((sum, item) => sum + itemPremiumTenths(item), 0);
  return { premium: Math.ceil(itemsTotalTenths / TENTHS_PER_UNIT) + PROCESSING_FEE };
};
